package com.vidaysalud.veterinaria.consultaservicio.service;import com.vidaysalud.veterinaria.consultaservicio.client.*;import com.vidaysalud.veterinaria.consultaservicio.dto.*;import com.vidaysalud.veterinaria.consultaservicio.exception.*;import com.vidaysalud.veterinaria.consultaservicio.model.Consulta;import com.vidaysalud.veterinaria.consultaservicio.repository.ConsultaRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;@Service @RequiredArgsConstructor @Transactional public class ConsultaService{private final ConsultaRepository r;private final MascotaClient m;private final VeterinarioClient v;private final CitaClient c;@Transactional(readOnly=true)public List<ConsultaResponseDTO>listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public ConsultaResponseDTO buscar(Integer id){return dto(get(id));}@Transactional(readOnly=true)public List<ConsultaResponseDTO>mascota(Integer id){return r.findByIdMascota(id).stream().map(this::dto).toList();}public ConsultaResponseDTO crear(ConsultaRequestDTO d){validar(d,null);return dto(r.save(map(new Consulta(),d)));}public ConsultaResponseDTO actualizar(Integer id,ConsultaRequestDTO d){validar(d,id);return dto(r.save(map(get(id),d)));}public void eliminar(Integer id){r.delete(get(id));}private void validar(ConsultaRequestDTO d,Integer id){m.validar(d.getIdMascota());v.validar(d.getIdVeterinario());if(d.getIdCita()!=null){c.validar(d.getIdCita());r.findByIdCita(d.getIdCita()).filter(x->!x.getIdConsulta().equals(id)).ifPresent(x->{throw new DatoDuplicadoException("La cita ya posee una consulta");});}}private Consulta get(Integer id){return r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Consulta no encontrada: "+id));}private Consulta map(Consulta x,ConsultaRequestDTO d){x.setIdMascota(d.getIdMascota());x.setIdVeterinario(d.getIdVeterinario());x.setIdCita(d.getIdCita());x.setFechaConsulta(d.getFechaConsulta());x.setMotivo(d.getMotivo());x.setDiagnostico(d.getDiagnostico());x.setObservaciones(d.getObservaciones());x.setPesoActual(d.getPesoActual());x.setTemperatura(d.getTemperatura());x.setCostoConsulta(d.getCostoConsulta());return x;}private ConsultaResponseDTO dto(Consulta x){return ConsultaResponseDTO.builder().idConsulta(x.getIdConsulta()).idMascota(x.getIdMascota()).idVeterinario(x.getIdVeterinario()).idCita(x.getIdCita()).fechaConsulta(x.getFechaConsulta()).motivo(x.getMotivo()).diagnostico(x.getDiagnostico()).observaciones(x.getObservaciones()).pesoActual(x.getPesoActual()).temperatura(x.getTemperatura()).costoConsulta(x.getCostoConsulta()).build();}}